## Broken Access Control Overview

Broken Access Control moved to #1 in the OWASP Top 10 2021, making it the most critical web application security risk. It occurs when users can act outside their intended permissions.

Common access control vulnerabilities:
- Violation of the principle of least privilege
- Bypassing access control checks by modifying URLs or API calls
- Viewing or editing other users' accounts
- Accessing API with missing access controls
- Escalating privileges

## Insecure Direct Object Reference (IDOR)

IDOR occurs when applications use user-supplied input to access objects directly:

### Attack Pattern

```
GET /api/users/123/profile  -> Returns user 123's profile
GET /api/users/124/profile  -> Returns user 124's profile (attacker changes ID)
```

### Vulnerable Code

```python
# VULNERABLE - No ownership verification
@app.route('/api/documents/<int:doc_id>')
def get_document(doc_id):
    doc = Document.query.get_or_404(doc_id)
    return jsonify(doc.to_dict())

# VULNERABLE - Query parameter manipulation
@app.route('/api/orders')
def get_orders():
    user_id = request.args.get('user_id')  # Attacker can change this
    orders = Order.query.filter_by(user_id=user_id).all()
    return jsonify([o.to_dict() for o in orders])
```

### Secure Code

```python
# SECURE - Verify ownership
def get_document(doc_id):
    doc = Document.query.get_or_404(doc_id)
    if doc.owner_id != current_user.id and not current_user.is_admin:
        abort(403)
    return jsonify(doc.to_dict())

# SECURE - Use session/user context
def get_orders():
    orders = Order.query.filter_by(user_id=current_user.id).all()
    return jsonify([o.to_dict() for o in orders])

# SECURE - Using authorization decorator
def require_owner(resource):
    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            resource = f(*args, **kwargs)
            if resource.owner_id != current_user.id:
                abort(403)
            return resource
        return decorated
    return decorator

@app.route('/api/documents/<int:doc_id>')
@require_owner(Document.query.get_or_404)
def get_document(doc_id):
    return jsonify(Document.query.get(doc_id).to_dict())
```

## Privilege Escalation

### Vertical Escalation

Normal user gains admin privileges:

```python
# VULNERABLE - Trusting client-side role
@app.route('/api/admin/users', methods=['DELETE'])
def delete_user():
    if request.json.get('role') != 'admin':
        abort(403)
    # Attacker can set role to 'admin'
    user_id = request.json['user_id']
    User.query.filter_by(id=user_id).delete()
    db.session.commit()
    return '', 204

# SECURE - Check role server-side
def delete_user():
    if not current_user.is_admin:
        abort(403)
    user_id = request.json['user_id']
    User.query.filter_by(id=user_id).delete()
    db.session.commit()
    return '', 204
```

### Horizontal Escalation

User accesses other users at the same privilege level:

```python
# VULNERABLE - No ownership check
@app.route('/api/profile/<int:user_id>', methods=['PUT'])
def update_profile(user_id):
    user = User.query.get_or_404(user_id)
    user.name = request.json['name']
    db.session.commit()
    return jsonify(user.to_dict())

# SECURE - Verify identity
def update_profile(user_id):
    if current_user.id != user_id:
        abort(403)
    user = User.query.get_or_404(user_id)
    user.name = request.json['name']
    db.session.commit()
    return jsonify(user.to_dict())
```

## CORS Misconfiguration

### Vulnerable Configuration

```javascript
// VULNERABLE - Allowing any origin
app.use(cors());  // Allows all origins

// VULNERABLE - Reflecting origin
app.use(cors({
    origin: function(origin, callback) {
        callback(null, origin);  // Reflects requesting origin
    }
}));

// VULNERABLE - Null origin allowed
app.use(cors({
    origin: ['https://example.com', 'null']
}));
```

### Secure Configuration

```javascript
// SECURE - Whitelist specific origins
const allowedOrigins = ['https://example.com', 'https://app.example.com'];

app.use(cors({
    origin: function(origin, callback) {
        if (!origin || allowedOrigins.includes(origin)) {
            callback(null, true);
        } else {
            callback(new Error('Not allowed by CORS'));
        }
    },
    credentials: true,
    methods: ['GET', 'POST', 'PUT', 'DELETE'],
    allowedHeaders: ['Content-Type', 'Authorization'],
    maxAge: 86400
}));

// SECURE - Explicit headers
app.use((req, res, next) => {
    res.header('Access-Control-Allow-Origin', 'https://example.com');
    res.header('Access-Control-Allow-Credentials', 'true');
    res.header('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE');
    res.header('Access-Control-Allow-Headers', 'Content-Type, Authorization');
    next();
});
```

## JWT Manipulation

### Algorithm Confusion Attack

```python
# VULNERABLE - Allowing algorithm switching
import jwt

def verify_jwt_vulnerable(token):
    # Attacker can set alg: 'none'
    return jwt.decode(token, SECRET_KEY, algorithms=None)

# SECURE - Fixed algorithm
def verify_jwt_secure(token):
    return jwt.decode(
        token,
        SECRET_KEY,
        algorithms=['HS256'],
        options={'require_exp': True}
    )
```

### JWT Claims Validation

```python
# SECURE - Complete JWT validation
def validate_jwt(token):
    try:
        payload = jwt.decode(
            token,
            SECRET_KEY,
            algorithms=['HS256'],
            options={
                'require': ['exp', 'iss', 'sub', 'aud'],
                'verify_exp': True,
                'verify_iss': True,
                'verify_aud': True
            }
        )

        # Additional checks
        if payload['iss'] != 'https://auth.example.com':
            raise jwt.InvalidIssuerError()

        if payload['aud'] != 'https://api.example.com':
            raise jwt.InvalidAudienceError()

        # Check token blacklist (for logout)
        if is_token_blacklisted(payload['jti']):
            raise jwt.InvalidTokenError()

        return payload
    except jwt.ExpiredSignatureError:
        raise AuthenticationError('Token expired')
    except jwt.InvalidTokenError as e:
        raise AuthenticationError(f'Invalid token: {e}')
```

## RBAC/ABAC Design

### Role-Based Access Control (RBAC)

```python
class Permission(Enum):
    READ = 'read'
    WRITE = 'write'
    DELETE = 'delete'
    ADMIN = 'admin'

ROLE_PERMISSIONS = {
    'viewer': [Permission.READ],
    'editor': [Permission.READ, Permission.WRITE],
    'admin': [Permission.READ, Permission.WRITE, Permission.DELETE, Permission.ADMIN]
}

def has_permission(user, permission):
    user_permissions = ROLE_PERMISSIONS.get(user.role, [])
    return permission in user_permissions

@app.route('/api/documents/<int:doc_id>', methods=['DELETE'])
def delete_document(doc_id):
    if not has_permission(current_user, Permission.DELETE):
        abort(403)
    doc = Document.query.get_or_404(doc_id)
    db.session.delete(doc)
    db.session.commit()
    return '', 204
```

### Attribute-Based Access Control (ABAC)

```python
# More granular, context-aware access control
def check_access(user, resource, action, context):
    # Check role
    if not has_role(user, resource.required_role):
        return False

    # Check ownership
    if resource.owner_id != user.id and not user.is_admin:
        return False

    # Check time-based restrictions
    if context.get('hour') < 9 or context.get('hour') > 17:
        if not user.is_admin:
            return False

    # Check IP whitelist
    if resource.restricted and context.get('ip') not in ALLOWED_IPS:
        return False

    return True

@app.route('/api/sensitive-data/<int:data_id>')
def get_sensitive_data(data_id):
    data = SensitiveData.query.get_or_404(data_id)

    context = {
        'ip': request.remote_addr,
        'hour': datetime.now().hour,
        'user_agent': request.user_agent.string
    }

    if not check_access(current_user, data, 'read', context):
        abort(403)

    return jsonify(data.to_dict())
```

## Key Takeaways

- Always verify access control server-side
- Deny by default - require explicit grants
- Use RBAC or ABAC for consistent access control
- Log access control failures for monitoring
- Rate limit API access to minimize automated attacks
- CORS must be properly configured
- JWT tokens must be validated completely
